import java.util.InputMismatchException;
import java.util.Scanner;

public class MortgageCalculator {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        while (true) {
            System.out.print("Enter the principal loan amount (must be positive): ");
            try {
                double principal = scanner.nextDouble();
                if (principal <= 0) {
                    System.out.println("Please enter a positive number.");
                    continue;
                }
                break;
            } catch (InputMismatchException e) {
                System.out.println("Invalid input. Please enter a number.");
                scanner.next(); // Clear invalid input
            }
        }

        while (true) {
            System.out.print("Enter the annual interest rate (must be between 0 and 100): ");
            try {
                double interestRate = scanner.nextDouble();
                if (interestRate < 0 || interestRate > 100) {
                    System.out.println("Please enter a number between 0 and 100.");
                    continue;
                }
                break;
            } catch (InputMismatchException e) {
                System.out.println("Invalid input. Please enter a number.");
                scanner.next(); // Clear invalid input
            }
        }

        while (true) {
            System.out.print("Enter the loan period in years (must be positive): ");
            try {
                int loanPeriod = scanner.nextInt();
                if (loanPeriod <= 0) {
                    System.out.println("Please enter a positive integer.");
                    continue;
                }
                break;
            } catch (InputMismatchException e) {
                System.out.println("Invalid input. Please enter an integer.");
                scanner.next(); // Clear invalid input
            }
        }

        double monthlyInterestRate = interestRate / 1200;
        double numberOfMonths = loanPeriod * 12;
        double monthlyMortgagePayment = calculateMortgage(principal, monthlyInterestRate, numberOfMonths);

        System.out.printf("The monthly mortgage payment is: $%.2f%n", monthlyMortgagePayment);
        System.out.print("Do you want to continue? (y/n): ");
        String response = scanner.next();
        if (response.equalsIgnoreCase("n")) {
            break;
        }
    }

    public static double calculateMortgage(double principal, double monthlyInterestRate, double numberOfMonths) {
        return principal * monthlyInterestRate * (1 + monthlyInterestRate) * Math.pow(1 + monthlyInterestRate, numberOfMonths) / (Math.pow(1 + monthlyInterestRate, numberOfMonths) - 1);
    }
}
