        (3, vec!["item7".to_string(), "item8".to_string(), "item9".to_string()]),
    ]);

    let page_data = data.get(&page_number).ok_or("Invalid page number.")?;

    let start_index = (page_number - 1) * page_size;
    let end_index = start_index + page_size;

    Ok(page_data[start_index..end_index].to_vec())
}

