namespace fs = std::filesystem;

void saveFilesToDirectory(const std::vector<std::string>& filenames, const std::string& directoryPath) {
    // Check if the directory exists
    if (!fs::exists(directoryPath)) {
        std::cout << "Error: Directory '" << directoryPath << "' does not exist." << std::endl;
        return;
    }

    // Check if the directory is writable
    if (!fs::is_directory(directoryPath) || !fs::status(directoryPath).permissions().has_perm(fs::perms::write)) {
        std::cout << "Error: Directory '" << directoryPath << "' is not writable." << std::endl;
        return;
    }

    for (const auto& filename : filenames) {
        // Construct the full paths of the file and the target directory
        fs::path filePath = fs::path(filename);
        fs::path targetDirectory = fs::path(directoryPath) / fs::path(filename).stem();

        // Check if the file exists
        if (!fs::exists(filePath)) {
            std::cout << "Error: File '" << filename << "' does not exist." << std::endl;
            continue;
        }

        try {
            // Move the file to the target directory
            fs::rename(filePath, targetDirectory);
            std::cout << "Successfully moved file '" << filename << "' to '" << directoryPath << "'." << std::endl;
        } catch (const fs::filesystem_error& e) {
            std::cout << "Error: Failed to move file '" << filename << "': " << e.what() << std::endl;
        }
    }
}
