use std::error::Error;
use std::fmt;

#[derive(Debug)]
enum AgeError {
    InvalidType,
    InvalidAgeRange(i32, i32),
}

impl fmt::Display for AgeError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            AgeError::InvalidType => write!(f, "Invalid type"),
            AgeError::InvalidAgeRange(min_age, max_age) => write!(f, "Invalid age range. Min age {} is not less than or equal to max age {}.", min_age, max_age),
        }
    }
}

impl Error for AgeError {}

fn age_validator(min_age: i32, max_age: i32) -> Result<String, AgeError> {
    if !std::any::type_name::<i32>() == "i32" {
        return Err(AgeError::InvalidType);
    }

    if min_age > max_age {
        return Err(AgeError::InvalidAgeRange(min_age, max_age));
    }

    Ok(format!("The age range is valid. Min age {} is less than or equal to max age {}.", min_age, max_age))
}

fn main() {
    match age_validator(25, 30) {
        Ok(result) => println!("{}", result),
        Err(err) => println!("{}", err),
    }

    match age_validator("twenty-five", 30) {
        Ok(result) => println!("{}", result),
        Err(err) => println!("{}", err),
    }

    match age_validator(25, "thirty") {
        Ok(result) => println!("{}", result),
        Err(err) => println!("{}", err),
    }
