import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.Node;
import org.w3c.dom.NodeList;
import org.xml.sax.InputSource;
import org.xml.sax.SAXException;

import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.ParserConfigurationException;
import javax.xml.transform.Source;
import javax.xml.transform.Transformer;
import javax.xml.transform.TransformerException;
import javax.xml.transform.TransformerFactory;
import javax.xml.transform.dom.DOMSource;
import javax.xml.transform.stream.StreamResult;
import java.io.File;
import java.io.IOException;
import java.io.StringReader;

public class ConfigurationLoader {

    public static class Configuration {
        private int port;
        private int timeout;

        public Configuration(int port, int timeout) {
            this.port = port;
            this.timeout = timeout;
        }

        public int getPort() {
            return port;
        }

        public int getTimeout() {
            return timeout;
        }
    }

    public static Configuration loadConfiguration(String xmlFilePath) {
        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            DocumentBuilder builder = factory.newDocumentBuilder();
            InputSource is = new InputSource(new StringReader(xmlFilePath));
            Document document = builder.parse(is);

            NodeList nodeList = document.getElementsByTagName("server");

            if (nodeList.getLength() == 0) {
                throw new RuntimeException("Server tag not found in XML file.");
            }

            Element serverElement = (Element) nodeList.item(0);

            NodeList portNodeList = serverElement.getElementsByTagName("port");
            if (portNodeList.getLength() == 0) {
                throw new RuntimeException("Port tag not found in server element.");
            }

            NodeList timeoutNodeList = serverElement.getElementsByTagName("timeout");
            if (timeoutNodeList.getLength() == 0) {
                throw new RuntimeException("Timeout tag not found in server element.");
            }

            int portValue = Integer.parseInt(portNodeList.item(0).getTextContent());
            int timeoutValue = Integer.parseInt(timeoutNodeList.item(0).getTextContent());

            return new Configuration(portValue, timeoutValue);

        } catch (ParserConfigurationException e) {
            System.out.println("Error parsing XML file: " + e.getMessage());
            return null;
        } catch (SAXException e) {
            System.out.println("Error parsing XML file: " + e.getMessage());
            return null;
        } catch (IOException e) {
            System.out.println("Error reading XML file: " + e.getMessage());
            return null;
        } catch (NumberFormatException e) {
            System.out.println("Invalid port or timeout value in XML file: " + e.getMessage());
            return null;
        }
    }

    public static void main(String[] args) {
        String xmlFilePath = "path_to_your_xml_file.xml";
        Configuration config = loadConfiguration(xmlFilePath);
        if (config != null) {
            System.out.println("Port: " + config.getPort());
            System.out.println("Timeout: " + config.getTimeout());
        }
    }
}
