fn filter_above_threshold(nums: Vec<f64>, threshold: i32) -> Vec<f64> {
    let threshold: f64 = threshold as f64;

    nums.into_iter()
        .filter_map(|num| match num {
            None => None,
            Some(n) => if n <= threshold { Some(n) } else { None },
        })
        .collect()
}

fn main() {
