#include <iostream>
#include <vector>
#include <queue>
#include <stdexcept>

std::vector<int> traverseGraph(const std::vector<std::vector<int>>& adjacencyMatrix, int startNode) {
    // Check if the adjacency matrix is valid
    if (adjacencyMatrix.empty() || adjacencyMatrix.size() == 0) {
        throw std::invalid_argument("Adjacency matrix cannot be empty");
    }

    // Check if the start node index is valid
    if (startNode < 0 || startNode >= adjacencyMatrix.size()) {
        throw std::out_of_range("Start node index out of range");
    }

    // Initialize the visited vector and the queue
    std::vector<bool> visited(adjacencyMatrix.size(), false);
    std::queue<int> queue;
    queue.push(startNode);
    visited[startNode] = true;

    // Initialize the result vector
    std::vector<int> result;

    // Perform BFS
    while (!queue.empty()) {
        int currentNode = queue.front();
        queue.pop();
        result.push_back(currentNode);

        // Add all unvisited neighbors to the queue
        for (int neighbor = 0; neighbor < adjacencyMatrix.size(); ++neighbor) {
            if (adjacencyMatrix[currentNode][neighbor] == 1 && !visited[neighbor]) {
                queue.push(neighbor);
                visited[neighbor] = true;
            }
        }
    }

    return result;
}

// Example usage
int main() {
    std::vector<std::vector<int>> adjacencyMatrix = {
        {0, 1, 1, 0},
        {0, 0, 1, 1},
        {0, 0, 0, 1},
        {0, 0, 0, 0}
    };

    try {
        std::vector<int> visitedOrder = traverseGraph(adjacencyMatrix, 0);
        for (int node : visitedOrder) {
            std::cout << node << " ";
        }
        std::cout << std::endl;
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

    return 0;
}
