/// Calculates the displacement of a moving object using the formula: 
/// displacement = initial_velocity * time + 0.5 * 9.8 * time^2.
///
/// # Parameters
/// * `initial_velocity` - The initial velocity of the object.
/// * `time` - The time in seconds.
///
/// # Returns
/// * `displacement` - The calculated displacement.
/// * `error` - An error message if the input time is negative.
///
/// # Example
/// ```rust
/// let initial_velocity = 10.0;
/// let time = 2.0;
/// let (displacement, error) = calculate_displacement(initial_velocity, time);
/// if let Some(error) = error {
///     println!("Error: {}", error);
/// } else {
///     println!("Displacement: {}", displacement);
/// }
/// ```
pub fn calculate_displacement(initial_velocity: f64, time: f64) -> (f64, Option<String>) {
    if time < 0.0 {
        return (0.0, Some("Error: Time cannot be negative.".to_string()));
    }
    let displacement = initial_velocity * time + 0.5 * 9.8 * time * time;
    (displacement, None)
}

fn main() {
    let initial_velocity = 10.0;
    let time = 2.0;
    let (displacement, error) = calculate_displacement(initial_velocity, time);
    if let Some(error) = error {
        println!("Error: {}", error);
    } else {
        println!("Displacement: {}", displacement);
    }
}
