def processUserData(userData):
    """
    Process user data by capitalizing names and filtering out users below age 18.

    Args:
        userData (dict): A dictionary mapping user IDs to user data.

    Returns:
        dict: A new dictionary with the processed user data.

    Raises:
        TypeError: If userData is not a dictionary.
        KeyError: If a user ID is missing from the userData dictionary.
    """
    if not isinstance(userData, dict):
        raise TypeError("userData must be a dictionary")

    processedData = {}

    for userId, userDataDict in userData.items():
        if not isinstance(userDataDict, dict):
            raise KeyError(f"User data for ID {userId} must be a dictionary")

        name = userDataDict.get("name", "")
        age = userDataDict.get("age", 0)

        if not isinstance(name, str):
            raise KeyError(f"Name for user ID {userId} must be a string")
        if not isinstance(age, int):
            raise KeyError(f"Age for user ID {userId} must be an integer")
        if age < 18:
            continue

        formattedName = name.capitalize()
        processedData[userId] = {
            "name": formattedName,
            "age": age
        }

    return processedData
