public class Main {
    public static boolean checkAccess(Set<String> blockedIps, String ipAddress) {
        // Regular expression pattern to validate IP address format
        String ipPattern = "^((25[0-5]|2[0-4][0-9]|[01]?[0-9][0-9]?)\\.){3}(25[0-5]|2[0-4][0-9]|[01]?[0-9][0-9]?)$";

        // Input validation: Check if the IP address format is correct
        if (!Pattern.matches(ipPattern, ipAddress)) {
            throw new IllegalArgumentException("Invalid IP address format");
        }

        // Check if the IP address is in the blocked set
        return !blockedIps.contains(ipAddress);
    }

    public static void main(String[] args) {
        Set<String> blockedIps = new HashSet<>(Set.of("192.168.1.1", "10.0.0.1"));
        System.out.println(checkAccess(blockedIps, "192.168.1.2"));  // true
        System.out.println(checkAccess(blockedIps, "10.0.0.1"));    // false
    }
