#include <iostream>

// Define the structure for a linked list node
struct Node {
    int value;
    Node* next;
};

// Function to create a new node with the given value
Node* createNode(int value) {
    Node* newNode = new Node();
    if (!newNode) {
        std::cerr << "Memory error: unable to allocate memory for new node" << std::endl;
        exit(1);
    }
    newNode->value = value;
    newNode->next = nullptr;
    return newNode;
}

// Function to process the linked list
Node* processLinkedList(Node* head) {
    // Check if the list is empty
    if (head == nullptr) {
        return nullptr;
    }

    // Initialize variables to keep track of the current node and its position
    Node* currentNode = head;
    int position = 1;

    // Traverse the linked list
    while (currentNode->next != nullptr) {
        // Move to the next node
        currentNode = currentNode->next;
        position++;
    }

    // Update the values of all nodes in the list
    currentNode = head;
    while (currentNode != nullptr) {
        // Multiply the value by its position (1-indexed)
        currentNode->value *= position;
        // Move to the next node
        currentNode = currentNode->next;
        position++;
    }

    // Return the modified linked list
    return head;
}

// Function to print the linked list
void printLinkedList(Node* head) {
    Node* currentNode = head;
    while (currentNode != nullptr) {
        std::cout << currentNode->value << " ";
