 * This class contains the uniqueElementAnalyzer method, which calculates the maximum, minimum, and arithmetic mean of a given set of integers.
 * 
 * @author [Your Name]
 */
public class UniqueElementAnalyzer {

    /**
     * Analyzes the provided set of integers to compute and return the maximum, minimum, and the arithmetic mean of the elements.
     * 
     * @param integerSet A set of integers.
     * @return An array containing the maximum, minimum, and arithmetic mean of the elements in the set.
     * @throws EmptySetException If the set is empty.
     */
    public static double[] uniqueElementAnalyzer( java.util.Set<Integer> integerSet) throws EmptySetException {

        // Check if the set is empty
        if (integerSet.isEmpty()) {
            throw new EmptySetException("The input set is empty.");
        }

        // Calculate the maximum element in the set
        int maxElement = Integer.MIN_VALUE;
        for (Integer element : integerSet) {
            if (element > maxElement) {
                maxElement = element;
            }
        }

        // Calculate the minimum element in the set
        int minElement = Integer.MAX_VALUE;
        for (Integer element : integerSet) {
            if (element < minElement) {
                minElement = element;
            }
        }

        // Calculate the arithmetic mean of the elements in the set
        double sum = 0;
        for (Integer element : integerSet) {
            sum += element;
        }
        double mean = sum / integerSet.size();

        // Return the maximum, minimum, and arithmetic mean as an array
        return new double[]{maxElement, minElement, mean};
    }

    /**
     * Custom exception for handling empty sets.
     */
    public static class EmptySetException extends Exception {
        public EmptySetException(String message) {
            super(message);
        }
    }

    public static void main(String[] args) {
        java.util.Set<Integer> integerSet = new java.util.HashSet<>();
        integerSet.add(10);
        integerSet.add(20);
        integerSet.add(30);

        try {
            double[] result = uniqueElementAnalyzer(integerSet);
            System.out.println("Maximum element: " + result[0]);
            System.out.println("Minimum element: " + result[1]);
            System.out.println("Arithmetic mean: " + result[2]);
        } catch (EmptySetException e) {
            System.out.println(e.getMessage());
        }
    }
}
