def calculate_grades(student_records, grade_map):
    """
    Calculate the average grade for each student and print a detailed report.

    Args:
    student_records (list): A list of dictionaries representing student names and IDs.
    grade_map (dict): A dictionary mapping student IDs to their grades.

    Returns:
    None
    """

    # Initialize an empty dictionary to store the sum of grades and count of grades for each student
    student_grades = {}

    # Iterate over each student record
    for student in student_records:
        # Get the student ID
        student_id = student['id']

        # Check if the student ID exists in the grade map
        if student_id in grade_map:
            # If the student ID exists, add the grade to the sum and increment the count
            if student_id not in student_grades:
                student_grades[student_id] = {'sum': grade_map[student_id], 'count': 1}
            else:
                student_grades[student_id]['sum'] += grade_map[student_id]
                student_grades[student_id]['count'] += 1
        else:
            # If the student ID does not exist, add it to the dictionary with a sum of 0 and a count of 0
            if student_id not in student_grades:
                student_grades[student_id] = {'sum': 0, 'count': 0}

    # Iterate over each student in the student records
    for student in student_records:
        # Get the student ID
        student_id = student['id']

        # Check if the student ID exists in the student_grades dictionary
        if student_id in student_grades:
            # Calculate the average grade
            average_grade = student_grades[student_id]['sum'] / student_grades[student_id]['count']
            print(f"Student Name: {student['name']}, Student ID: {student_id}, Average Grade: {average_grade:.2f}")
        else:
            # If the student ID does not exist, print "Not Available"
            print(f"Student Name: {student['name']}, Student ID: {student_id}, Average Grade: Not Available")

