use std::collections::{HashMap, HashSet, VecDeque};

#[derive(Debug)]
enum TraversalApproach {
    DFS,
    BFS,
}

#[derive(Debug)]
struct Graph {
    nodes: HashMap<String, Vec<String>>,
}

impl Graph {
    fn new() -> Self {
        Graph {
            nodes: HashMap::new(),
        }
    }

    fn add_node(&mut self, node: &str) {
        self.nodes.entry(node.to_string()).or_insert(Vec::new());
    }

    fn add_edge(&mut self, start: &str, end: &str) {
        self.nodes.get_mut(start).unwrap().push(end.to_string());
    }
}

fn find_path(graph: &Graph, start: &str, end: &str, approach: TraversalApproach) -> Option<Vec<String>> {
    let mut visited = HashSet::new();
    let mut stack = VecDeque::new();

    match approach {
        TraversalApproach::DFS => {
            stack.push_back(start.to_string());
            visited.insert(start.to_string());
            while let Some(node) = stack.pop_front() {
                if node == end {
                    return Some(vec![node]);
                }
                for neighbor in graph.nodes.get(&node).unwrap().clone() {
                    if !visited.contains(neighbor) {
                        visited.insert(neighbor.clone());
                        stack.push_back(neighbor);
                    }
                }
            }
        }
        TraversalApproach::BFS => {
            let mut queue = VecDeque::new();
            queue.push_back(start.to_string());
            visited.insert(start.to_string());
            while let Some(node) = queue.pop_front() {
                if node == end {
                    return Some(vec![node]);
                }
                for neighbor in graph.nodes.get(&node).unwrap().clone() {
                    if !visited.contains(neighbor) {
                        visited.insert(neighbor.clone());
                        queue.push_back(neighbor);
                    }
                }
            }
        }
    }

    None
}

fn main() {
    let mut graph = Graph::new();
    graph.add_node("A");
    graph.add_node("B");
    graph.add_node("C");
    graph.add_node("D");
    graph.add_node("E");

    graph.add_edge("A", "B");
    graph.add_edge("A", "C");
    graph.add_edge("B", "D");
    graph.add_edge("C", "E");

    match find_path(&graph, "A", "E", TraversalApproach::DFS) {
        Some(path) => println!("DFS Path: {:?}", path),
        None => println!("No path found"),
    }

    match find_path(&graph, "A", "E", TraversalApproach::BFS) {
        Some(path) => println!("BFS Path: {:?}", path),
        None => println!("No path found"),
    }
}
