#include <iostream>
#include <vector>
#include <queue>
#include <limits>
#include <unordered_map>

using namespace std;

struct Node {
    int id;
    int distance;
};

struct CompareNodes {
    bool operator()(const Node& a, const Node& b) {
        return a.distance > b.distance;
    }
};

int findShortestPath(const unordered_map<int, vector<int>>& graph, int start, int end) {
    if (graph.find(start) == graph.end() || graph.find(end) == graph.end()) {
        throw runtime_error("Starting or ending node does not exist in the graph");
    }

    unordered_map<int, int> distances;
    for (const auto& node : graph) {
        distances[node.first] = numeric_limits<int>::max();
    }
    distances[start] = 0;

    priority_queue<Node, vector<Node>, CompareNodes> priorityQueue;
    priorityQueue.push({start, 0});

    while (!priorityQueue.empty()) {
        Node currentNode = priorityQueue.top();
        priorityQueue.pop();

        if (currentNode.id == end) {
            return currentNode.distance;
        }

        for (int neighbor : graph.at(currentNode.id)) {
            int newDistance = currentNode.distance + 1;
            if (newDistance < distances[neighbor]) {
                distances[neighbor] = newDistance;
                priorityQueue.push({neighbor, newDistance});
            }
        }
    }

    throw runtime_error("No path found from starting node to ending node");
}

int main() {
    unordered_map<int, vector<int>> graph = {
        {1, {2, 3}},
        {2, {1, 4}},
        {3, {1, 5}},
        {4, {2, 6}},
        {5, {3}},
        {6, {4}}
    };

    try {
        cout << findShortestPath(graph, 1, 6) << endl;  // Output: 3
    } catch (const exception& e) {
        cerr << e.what() << endl;
    }

    return 0;
}
