import java.util.*;

public class Main {

    public static List<String> analyzeGraphTraversal(Map<String, List<String>> graph, boolean useBFS) {
        Set<String> visited = new HashSet<>();
        List<String> traversalOrder = new ArrayList<>();

        if (graph.isEmpty()) {
            return traversalOrder;
        }

        if (useBFS) {
            Queue<String> queue = new LinkedList<>(graph.keySet());
            while (!queue.isEmpty()) {
                String node = queue.poll();
                if (!visited.contains(node)) {
                    visited.add(node);
                    traversalOrder.add(node);
                    queue.addAll(graph.get(node));
                }
            }
        } else {
            for (String node : graph.keySet()) {
                dfs(graph, node, visited, traversalOrder);
            }
        }

        return traversalOrder;
    }

    private static void dfs(Map<String, List<String>> graph, String node, Set<String> visited, List<String> traversalOrder) {
        visited.add(node);
        traversalOrder.add(node);
        for (String neighbor : graph.get(node)) {
            if (!visited.contains(neighbor)) {
                dfs(graph, neighbor, visited, traversalOrder);
            }
        }
    }

    public static void main(String[] args) {
        Map<String, List<String>> graph = new HashMap<>();
        graph.put("A", Arrays.asList("B", "C"));
        graph.put("B", Arrays.asList("A", "D", "E"));
        graph.put("C", Arrays.asList("A", "F"));
        graph.put("D", Arrays.asList("B"));
        graph.put("E", Arrays.asList("B", "F"));
        graph.put("F", Arrays.asList("C", "E"));

        System.out.println(analyzeGraphTraversal(graph, true));
        System.out.println(analyzeGraphTraversal(graph, false));
    }
}
