fn expireSessions(active_sessions: &mut HashSet<String>, expiration_time: i32) {
    let now = SystemTime::now().duration_since(SystemTime::UNIX_EPOCH).unwrap().as_secs();
    let expiration_time = now as i32 + expiration_time;

    for token in active_sessions.iter() {
        if expiration_time <= now {
            println!("Session token {} has expired.", token);
        } else {
            println!("Session token {} has not expired yet.", token);
        }
    }

    active_sessions.retain(|token| {
        let expiration_time = now as i32 + expiration_time;
        expiration_time > now
    });

    if active_sessions.is_empty() {
        println!("No tokens are currently active.");
    }
}
