#include <iostream>
#include <stdexcept>

float calculateMortgagePayment(float principal, float annualInterestRate, int loanTerm) {
    if (principal <= 0) {
        throw std::invalid_argument("Principal must be greater than zero.");
    }
    if (annualInterestRate <= 0) {
        throw std::invalid_argument("Annual interest rate must be greater than zero.");
    }
    if (loanTerm <= 0) {
        throw std::invalid_argument("Loan term must be greater than zero.");
    }

    float monthlyInterestRate = annualInterestRate / 1200;
    int numberOfMonths = loanTerm * 12;

    float monthlyPayment = principal * monthlyInterestRate * pow(1 + monthlyInterestRate, numberOfMonths) / (pow(1 + monthlyInterestRate, numberOfMonths) - 1);
    return monthlyPayment;
}

int main() {
    try {
        float principal = 200000;
        float annualInterestRate = 4.5;
        int loanTerm = 30;
        float monthlyPayment = calculateMortgagePayment(principal, annualInterestRate, loanTerm);
        std::cout << "Monthly payment: " << monthlyPayment << std::endl;
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
        return 1;
    }

    return 0;
}
