#include <iostream>
#include <limits>
#include <vector>

std::vector<int> computeShortestPathFromNode(const std::vector<std::vector<int>>& graph, int startNode) {
    if (startNode < 0 || startNode >= graph.size()) {
        throw std::out_of_range("Starting node index is beyond the matrix scope.");
    }

    const int numNodes = graph.size();
    std::vector<int> shortestDistances(numNodes, std::numeric_limits<int>::max());
    shortestDistances[startNode] = 0;

    std::vector<bool> visited(numNodes, false);
    for (int i = 0; i < numNodes; ++i) {
        int minDistance = std::numeric_limits<int>::max();
        int minIndex = -1;
        for (int j = 0; j < numNodes; ++j) {
            if (!visited[j] && shortestDistances[j] < minDistance) {
                minDistance = shortestDistances[j];
                minIndex = j;
            }
        }
        visited[minIndex] = true;
        for (int j = 0; j < numNodes; ++j) {
            if (!visited[j] && graph[minIndex][j] != 0 && shortestDistances[minIndex] + graph[minIndex][j] < shortestDistances[j]) {
                shortestDistances[j] = shortestDistances[minIndex] + graph[minIndex][j];
            }
        }
    }

    std::vector<int> shortestPath;
    int currentNode = numNodes - 1;
    while (currentNode != startNode) {
        shortestPath.push_back(currentNode);
        for (int i = 0; i < numNodes; ++i) {
            if (graph[currentNode][i] != 0 && shortestDistances[currentNode] == shortestDistances[i] + graph[currentNode][i]) {
                currentNode = i;
                break;
            }
        }
    }
    shortestPath.push_back(startNode);
    std::reverse(shortestPath.begin(), shortestPath.end());
    return shortestPath;
}

int main() {
    std::vector<std::vector<int>> graph = {
        {0, 4, 0, 0, 0, 0, 0, 8, 0},
        {4, 0, 8, 0, 0, 0, 0, 11, 0},
        {0, 8, 0, 7, 0, 4, 0, 0, 2},
        {0, 0, 7, 0, 9, 14, 0, 0, 0},
        {0, 0, 0, 9, 0, 10, 0, 0, 0},
        {0, 0, 4, 14, 10, 0, 2, 0, 0},
        {0, 0, 0, 0, 0, 2, 0, 1, 6},
        {8, 11, 0, 0, 0, 0, 1, 0, 7},
        {0, 0, 2, 0, 0, 0, 6, 7, 0}
    };
    int startNode = 0;
    try {
        std::vector<int> shortestPath = computeShortestPathFromNode(graph, startNode);
        for (int node : shortestPath) {
            std::cout << node << " ";
        }
        std::cout << std::endl;
    } catch (const std::exception& e) {
        std::cerr << e.what() << std::endl;
    }

    return 0;
}
