    let mut filtered_ids: HashSet<i32> = HashSet::new();

    for id in ids {
        match id {
            id if id <= 0 => {
                log::warn!("Invalid post ID: {}", id);
                continue;
            }
            _ => {}
        }

        let post = BlogPost { id, status: PostStatus::Published };

        if include_drafts || post.status == PostStatus::Published {
            filtered_ids.insert(id);
        }
    }

    Ok(filtered_ids)
}

fn main() {
    let ids = vec![1, 2, 3, 4, 5, 6];
    let include_drafts = true;

    match filter_blog_posts(ids, include_drafts) {
        Ok(filtered_ids) => {
            log::info!("Filtered post IDs: {:?}", filtered_ids);
        }
        Err(e) => {
            log::error!("Error filtering post IDs: {}", e);
        }
    }
