struct User {
    age: Option<i32>,
    occupation: Option<String>,
    city: Option<String>,
}

impl User {
    fn new(age: i32, occupation: String, city: String) -> Self {
        User { age: Some(age), occupation, city }
    }
}

impl fmt::Display for User {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "age: {}, occupation: {}, city: {}", self.age.unwrap_or(-1), self.occupation, self.city)
    }
}

impl User {
    fn aggregate_stats(&self) -> (Option<f64>, Option<String>, Option<String>) {
        let avg_age = self.age.map(|age| age as f64 / self.occupation.as_ref().map_or(0, | occupation| 1));
        let most_common_occupation = self.occupation.clone().map(|occupation| (occupation, 1));
        let most_common_city = self.city.clone().map(|city| (city, 1));

        (avg_age, most_common_occupation, most_common_city)
    }
}

fn aggregateUserData(users: HashMap<String, User>) -> Result<(), Box<dyn Error>> {
    if users.is_empty() {
        return Err(Box::new(io::Error::new(
            io::ErrorKind::Other,
            "The user map is empty",
        )));
    }

    let mut total_age = 0;
    let mut most_common_occupation = String::new();
    let mut most_common_occupation_count = 0;
    let mut most_common_city = String::new();
    let mut most_common_city_count = 0;

    for user in users.values() {
        if let Some(age) = user.age {
            total_age += age;
        }
        if let Some(occupation) = user.occupation {
            if occupation.len() > most_common_occupation.len() {
                most_common_occupation = occupation;
                most_common_occupation_count = 1;
            } else if occupation.len() == most_common_occupation.len() {
                most_common_occupation_count += 1;
            }
        }
        if let Some(city) = user.city {
            if city.len() > most_common_city.len() {
                most_common_city = city;
                most_common_city_count = 1;
            } else if city.len() == most_common_city.len() {
                most_common_city_count += 1;
            }
        }
    }

    let avg_age = if total_age == 0 {
        None
    } else {
        Some(total_age as f64 / users.len() as f64)
    };
    let most_common_occupation = if most_common_occupation_count == 0 {
        None
    } else {
        Some(most_common_occupation)
    };
    let most_common_city = if most_common_city_count == 0 {
        None
    } else {
        Some(most_common_city)
    };

    println!("Average Age: {:?}", avg_age);
    println!("Most Common Occupation: {:?}", most_common_occupation);
    println!("Most Common City: {:?}", most_common_city);

    Ok(())
}

fn main() -> Result<(), Box<dyn Error>> {
    let users: HashMap<String, User> = HashMap::from([
        ("user1".to_string(), User::new(25, "Engineer".to_string(), "New York".to_string())),
        ("user2".to_string(), User::new(30, "Doctor".to_string(), "Los Angeles".to_string())),
        ("user3".to_string(), User::new(35, "Engineer".to_string(), "New York".to_string())),
    ]);

    aggregateUserData(users)?;

    Ok(())
}
