#include <iostream>
#include <sqlite3.h>
#include <json/json.h>

void updateTableSchema(const std::string& tableName, const Json::Value& newSchema) {
    // Check if the table exists
    sqlite3* db;
    char* errorMessage;
    int rc = sqlite3_open("database.db", &db);
    if (rc) {
        std::cerr << "Can't open database: " << sqlite3_errmsg(db) << std::endl;
        sqlite3_close(db);
        return;
    }

    rc = sqlite3_exec(db, "SELECT name FROM sqlite_master WHERE type='table' AND name=?", &tableName, nullptr, &errorMessage);
    if (rc != SQLITE_OK && rc != SQLITE_ROW) {
        std::cerr << "Table not found: " << errorMessage << std::endl;
        sqlite3_free(errorMessage);
        sqlite3_close(db);
        return;
    }

    // Update the schema
    for (const auto& column : newSchema) {
        std::string columnName = column.isObject() ? column["column_name"].asString() : column.asString();
        std::string columnType = column.isObject() ? column["data_type"].asString() : column.asString();

        if (columnName.empty() || columnType.empty()) {
            std::cerr << "Invalid column definition: " << columnName << ", " << columnType << std::endl;
            sqlite3_close(db);
            return;
        }

        std::string query = "ALTER TABLE " + tableName + " ALTER COLUMN " + columnName + " TYPE " + columnType;
        rc = sqlite3_exec(db, query.c_str(), nullptr, nullptr, &errorMessage);
        if (rc != SQLITE_OK) {
            std::cerr << "Error updating schema: " << errorMessage << std::endl;
            sqlite3_free(errorMessage);
        }
    }

    sqlite3_close(db);
}
